@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@if (OnClick.HasDelegate)
{
    <CascadingValue TValue="Lumeo.Density?" Value="EffectiveDensity" IsFixed="false">
        <div @ref="_el"
             id="@_cardId"
             class="@CssClass"
             role="button"
             tabindex="0"
             @onclick="OnClick"
             @onkeydown="HandleKeyDown"
             @attributes="AdditionalAttributes">
            @ChildContent
        </div>
    </CascadingValue>
}
else
{
    <CascadingValue TValue="Lumeo.Density?" Value="EffectiveDensity" IsFixed="false">
        <div class="@CssClass" @attributes="AdditionalAttributes">
            @ChildContent
        </div>
    </CascadingValue>
}

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }

    /// <summary>
    /// Optional click handler. When set, the card becomes a button-role
    /// interactive surface with <c>cursor-pointer</c>, focus-visible ring,
    /// keyboard activation, and honours <see cref="PressEffect"/>.
    /// </summary>
    [Parameter] public EventCallback<Microsoft.AspNetCore.Components.Web.MouseEventArgs> OnClick { get; set; }

    /// <summary>
    /// Visual feedback when the card is pressed (only applies when
    /// <see cref="OnClick"/> is bound). Default is
    /// <see cref="Button.ButtonPressEffect.None"/>.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    /// <summary>Surface style — four tiers, matching the depth ramp of shadcn
    /// (bordered → shadow), Radix Themes (<c>ghost|surface|classic</c>) and
    /// MudBlazor (<c>Outlined</c> / <c>Elevation</c>):
    /// <list type="bullet">
    /// <item><c>Default</c> — bordered card with the card background (no shadow).</item>
    /// <item><c>Flat</c> — drops the border + card background; a content-only
    /// surface that (with <see cref="OnClick"/>) is the natural primitive for
    /// clickable list rows, replacing the <c>Ghost button + !p-0</c> workaround.</item>
    /// <item><c>Outline</c> — bordered but with a transparent fill, so the page
    /// background shows through; for cards layered on a coloured/!card surface.</item>
    /// <item><c>Elevated</c> — bordered card background plus a <c>shadow-sm</c> for
    /// a raised, floating feel (shadcn's default Card depth).</item>
    /// </list></summary>
    [Parameter] public CardVariant Variant { get; set; } = CardVariant.Default;

    /// <summary>Per-card density override. Tightens internal padding when
    /// rendered inside dense layouts (DataGrid row, dashboard tile grid).
    /// Falls back to ancestor <see cref="DensityScope"/> or
    /// <c>Comfortable</c>.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private Microsoft.AspNetCore.Components.ElementReference _el;
    private readonly string _cardId = LumeoIds.New("card");

    private bool IsInteractive => OnClick.HasDelegate;

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private Lumeo.Density? EffectiveDensity => Density ?? InheritedDensity;

    private string SurfaceClass => Variant switch
    {
        // Flat: no border / card bg / shadow — a content-only surface. Keeps
        // the rounded corners so the hover/focus ring still reads as a row.
        CardVariant.Flat => "rounded-lg text-card-foreground",
        // Outline: bordered but unfilled (transparent), so a coloured ancestor
        // shows through. Distinct from Default purely by the absent bg-card.
        CardVariant.Outline => "rounded-lg border border-border/40 text-card-foreground",
        // Elevated: Default surface raised with a resting shadow (shadcn's
        // default Card depth / Radix "classic").
        CardVariant.Elevated => "rounded-lg border border-border/40 bg-card text-card-foreground shadow-sm",
        _ => "rounded-lg border border-border/40 bg-card text-card-foreground",
    };

    private string CssClass => Cx.Merge(
        SurfaceClass,
        Cx.When(IsInteractive, "cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 hover:bg-accent/30"),
        IsInteractive ? PressEffectClass : null,
        Class);

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (!IsInteractive) return;
        if (e.Key == "Enter" || e.Key == " ")
        {
            await OnClick.InvokeAsync(new Microsoft.AspNetCore.Components.Web.MouseEventArgs());
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && IsInteractive)
        {
            try
            {
                // div[role=button]: Space activated the card AND scrolled the
                // page (no native key synthesis on a div). Suppress only
                // Space's default; Enter has none on a div.
                await Interop.RegisterPreventDefaultKeys(
                    _cardId,
                    new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
                _pdRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }

        // Reconcile the ripple pointerdown listener with the LIVE
        // PressEffect/IsInteractive on EVERY render — not latched on firstRender
        // (triage wave-3 #6, mirrors Button.razor). A runtime None->Ripple flip
        // must now attach, and a Ripple->None (or interactive->non-interactive)
        // flip must detach the otherwise-leaked listener.
        var wantRipple = IsInteractive && PressEffect == Button.ButtonPressEffect.Ripple;
        if (wantRipple && !_rippleAttached)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
                _rippleAttached = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
        else if (!wantRipple && _rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (InvalidOperationException) { }
            _rippleAttached = false;
        }
    }

    private bool _pdRegistered;

    // Whether the JS pointerdown ripple listener is currently bound to _el.
    // Tracked so attach/detach is reconciled against the live PressEffect on
    // every render (not latched on firstRender) and torn down on dispose.
    private bool _rippleAttached;

    public async ValueTask DisposeAsync()
    {
        if (_rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
            _rippleAttached = false;
        }

        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_cardId);
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public enum CardVariant { Default, Flat, Outline, Elevated }
}

@namespace Lumeo

<div class="@(Cx.Merge(PadClass, Class))" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string PadClass => Density switch
    {
        Lumeo.Density.Compact => "p-4 pt-0",
        Lumeo.Density.Spacious => "p-8 pt-0",
        _ => "p-6 pt-0"
    };
}

